import React, { useState } from "react";
import {Link,Routes, Route, Navigate, BrowserRouter} from 'react-router-dom';
import Login from "./Login";
import './Design.css';
import  axios from 'axios';
document.body.style.overflow = "hidden"

function Signup(){

/*const[email,setEmail]=useState('');
const[usertype,setUserType]=useState('');
const[username,setUsername]=useState('');
const[mobile,setMobile]=useState('');
const[password,setPassword]=useState('');
const[confirmpassword,setConfirmPassword]=useState('');*/

const [user,setUser]=useState({
email:'',
usertype:'',
username:'',
mobile:'',
password:'',
confirmpassword:''
})

const onInputChange = e =>{
setBook({...user,[e.target.name]:e.target.value})
}

const {email,usertype,username,mobile,password,confirmpassword} = user;

    const FormHandle = e => {
        e.preventDefault();
        addDataToServer(user)
    }

    const addDataToServer = (data) => {
        axios.post("http://localhost:8080/signup", data).then(
            (response) => {
                console.log(response);
                alert("Book Added Successfully");
            }, (error) => {
                console.log(error);
                alert("Operation failed");
            }
        );
    }


const handleClick=(e)=>{
e.preventDefault()
const user={"type":usertype,"email":email,"username":username, "mobile": mobileNumber, "password": password, "repassword": confirmpassword}
console.log(user)
fetch("/signup",
{
method:"POST",
mode:"cors",
credentials: 'include',
headers:{"Content-Type":"application/json", 'Access-Control-Allow-Origin':'*'},
body:JSON.stringify(user)
}).then(()=>{alert("Registration Completed")})
}


    return (
    <>  
<div className="bg1">
<br></br>
<br></br>
<div className="titlebar">
        Register
    </div>

    <div className="form">
        <form >
        <br></br>
            <select id="usertype" value={usertype} onChange={(e)=>setUserType(e.target.value)}>
                <option id = "admin" value = "admin" >Admin</option>
                <option id = "user" value = "user">User</option>
            </select>
            <br></br>
            <input placeholder = "Email" type = "email" id = "email" name='email' value={email} onChange={(e)=>setEmail(e.target.value)}></input>
            <br></br>
            <input placeholder = "Username" type = "text" id =  "username" name = "username" value={username} onChange={(e)=>setUsername(e.target.value)}></input>
            <br></br>
            <input placeholder = "Mobile Number" type = "text" id =  "mobile" name = "mobile" value={mobile} onChange={(e)=>setMobile(e.target.value)}></input>
            <br></br>
            <input placeholder = "Password" type = "text" id =  "password" name = "password" value={password} onChange={(e)=>setPassword(e.target.value)}></input>
            <br></br>
            <input placeholder = "Confirm Password" type = "text" id =  "confirmpassword" name = "confirmpassowrd" value={confirmpassword} onChange={(e)=>setConfirmPassword(e.target.value)}></input>
        </form>
        <div className="center">
        <button id = "submitButton" type='submit' value="Submit" onClick={FormHandle}> Submit </button>
        </div>
        <br></br>
    </div>
    <p >Already a Member?  < Link to = "/Login" className="link"> Login</Link> </p>
    <br></br>
</div>
    </>)
}



export default Signup;
